    #[doc = " Macro that returns a recursive function that (semi-)automatically captures."]
    #[doc = ""]
    #[doc = " # Example"]
    #[doc = " default version"]
    #[doc = " ```"]
    #[doc = " # use competitive::crecurse;"]
