    #[doc = "                 *res += coeff * x;"]
    #[doc = "             }"]
    #[doc = "             // (3) call macro to recurse"]
    #[doc = "             mul!(x + x, y / 2);"]
    #[doc = "         }"]
    #[doc = "     }"]
    #[doc = " )(10, 19); // (4) macro returns captured version of the recursive function"]
    #[doc = " assert_eq!(res, coeff * 10 * 19);"]
    #[doc = " ```"]
